/** Récupère la valeur d'un élément par id (chaîne vide si absent). */
function getDomVal(id) {
  return document.getElementById(id)?.value || '';
}

/** Définit la valeur d'un élément par id si l'élément existe. */
function setDomVal(id, val) {
  const el = document.getElementById(id);
  if (el) el.value = val;
}

/** Indique si le format actif est un format soumission. */
function isSubmitFormat(fmt) {
  fmt = fmt || getDomVal('page-format');
  return fmt === 'SUBMIT_AMI' || fmt === 'SUBMIT_STD';
}

/** Nettoie le texte pour les analyses (retire balises image/note, normalise ponctuation). */
function cleanForCounting(text) {
  return text
    .replace(/\[NOTE:[^\]]*\]/gi, '')
    .replace(/\[HL:\w+\s([^\|]*?)(?:\|[^\]]*)?\]/gi, '$1')
    .replace(/\[TAG:\w+\s([^\]]*)\]/gi, '$1')
    .replace(/\[IMAGE:[^\]]*\]/gi, ' ')
    .replace(/\r\n/g, '\n')
    .replace(/—|–/g, ' ')
    .replace(/['']/g, "'")
    .replace(/[""«»]/g, '"');
}

/** Compte les mots d'un texte (retire balises image/note avant comptage). */
function countWords(txt) {
  const clean = txt
    .replace(/\[NOTE:[^\]]*\]/gi, '')
    .replace(/\[HL:\w+\s([^\|]*?)(?:\|[^\]]*)?\]/gi, '$1')
    .replace(/\[TAG:\w+\s([^\]]*)\]/gi, '$1')
    .replace(/\[IMAGE:[^\]]*\]/gi, '');
  return (clean.match(/\S+/g) || []).length;
}

/** Sauvegarde/restaure une préférence simple dans localStorage. */
function lsPref(action, key, inputId) {
  try {
    if (action === 'save') {
      const v = getDomVal(inputId);
      localStorage.setItem(key, v);  // Enregistre même si vide (efface la valeur)
    } else {
      const v = localStorage.getItem(key);
      if (v !== null) setDomVal(inputId, v);
    }
  } catch(e) {}
}

/** Retourne la date du jour au format YYYY-MM-DD. */
function _todayStr() {
  return new Date().toISOString().slice(0, 10);
}

/**
 * Extrait tous les mots (en minuscules, longueur > 1) depuis les noms,
 * variantes, et champs optionnels des fiches personnages et lieux.
 * Utilisé par buildLtParams, ltPostFilter et le moteur de style local.
 */
function getKnownProperWords() {
  const words = new Set();
  const addWords = str => {
    if (!str) return;
    str.split(/[\s\-\/]+/).forEach(w => {
      const clean = w.replace(/[^a-zA-ZàâéèêëîïôùûüœçÀÂÉÈÊËÎÏÔÙÛÜŒÇ]/g, '');
      if (clean.length > 1) words.add(clean.toLowerCase());
    });
  };
  const addVariants = str => {
    if (!str) return;
    str.split(/[,;]+/).map(v => v.trim()).filter(Boolean).forEach(v => addWords(v));
  };
  getPersos().forEach(p => {
    addWords(p.nom);
    addVariants(p.variantes);
    addWords(p.origine);   // ex: "Eindonnien", "noblesse du Nord"
    addVariants(p.langage); // ex: "parle en argot", noms de dialectes
  });
  getLieux().forEach(l => {
    addWords(l.nom);
    addVariants(l.variantes);
    addVariants(l.peuples);     // ex: "Elfes des Cendres, Nains du Fer"
    addWords(l.parent);         // ex: "Empire d'Astral"
    addWords(l.gouvernance);    // ex: "Roi Aldren III"
  });
  return words;
}

/** Retourne l'élément textarea principal (raw-input). */
function getTA() { return document.getElementById('raw-input'); }

/** Génère le HTML d'un spinner de chargement pour les panneaux outils. */
function spinnerHtml(msg) {
  return `<div class="wt-spinner"><div class="wt-spinner-ring"></div>${msg}</div>`;
}

/**
 * Désactive un bouton pendant une opération async, le réactive après.
 */
async function withBtnBusy(btn, labelDuring, labelAfter, asyncFn) {
  if (!btn) { await asyncFn(); return; }
  btn.disabled = true;
  btn.textContent = labelDuring;
  try { await asyncFn(); } finally {
    btn.disabled = false;
    btn.textContent = labelAfter;
  }
}

/**
 * Vérifie la présence d'un texte et d'une clé IA. Retourne true si ok.
 */
function _requireTextAndKey() {
  if (!getDomVal('raw-input').trim()) {
    showToast(_t('toast_no_text'), 2500, 'error'); return false;
  }
  const provCfg = _getProviderConfig(_wtProvider);
  const key = (provCfg.key || _wtApiKey || '').trim();
  if (!key) {
    const provNames = { claude: 'Claude', openai: 'OpenAI', gemini: 'Gemini', groq: 'Groq', openrouter: 'OpenRouter' };
    const pName = provNames[_wtProvider] || _wtProvider || '?';
    showToast(_t('toast_no_api_key').replace('{provider}', pName), 5000, 'error');
    return false;
  }
  return true;
}

/**
 * Rend des lignes IA (format "— **Titre**") en blocs HTML bordés.
 */
function renderAiLines(lines) {
  return lines
    .filter(l => l.trim())
    .map(l => {
      const clean = escHtml(l.trim()).replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>');
      if (clean.startsWith('—') || clean.startsWith('-')) {
        return `<div style="margin-bottom:7px;padding-left:8px;border-left:2px solid var(--accent-light);">${clean.replace(/^[—\-]\s*/, '')}</div>`;
      }
      return `<div style="margin-bottom:4px;">${clean}</div>`;
    })
    .join('');
}

/** Bouton Fermer sous un bloc IA inline. */
function _aiCloseBtn(boxId) {
  return `<div style="text-align:right;margin-top:8px;">
    <button onclick="document.getElementById('${boxId}').style.display='none'"
      style="font-size:9.5px;background:none;border:none;cursor:pointer;color:var(--ink-muted);">✕ Fermer</button>
  </div>`;
}

/**
 * Branche API OpenAI-compatible partagée entre OpenAI et Groq.
 */
async function _callOpenAIcompat(url, key, system, user, model, tokens, label, signal) {
  const isOpenRouter = url.includes('openrouter.ai');
  const headers = {
    'Content-Type': 'application/json',
    'Authorization': 'Bearer ' + key,
  };
  if (isOpenRouter) {
    headers['HTTP-Referer'] = 'https://atelier-edition.local';
    headers['X-Title'] = 'Atelier Edition';
  }
  const res = await fetch(url, {
    method: 'POST',
    signal: signal || undefined,
    headers,
    body: JSON.stringify({
      model, max_tokens: tokens,
      messages: [{ role: 'system', content: system }, { role: 'user', content: user }],
    }),
  });
  if (!res.ok) {
    const err = await res.json().catch(() => ({}));
    throw new Error(err.error?.message || `Erreur API ${label} ` + res.status);
  }
  const data = await res.json();
  const msg = data.choices?.[0]?.message;
  // Modèles reasoning (DeepSeek, Qwen, GLM, Tencent…) : le raisonnement interne
  // peut apparaître dans content entre <think>…</think>, ou dans reasoning_content.
  // On préfère content s'il existe, mais on purge les balises <think>.
  let text = msg?.content
    || msg?.reasoning_content
    || msg?.reasoning
    || data.choices?.[0]?.text
    || null;
  if (text) {
    // Supprimer les blocs <think>…</think> (raisonnement interne visible)
    text = text.replace(/<think>[\s\S]*?<\/think>/gi, '').trim();
    // Si après nettoyage le texte est vide, retomber sur reasoning_content
    if (!text) text = msg?.reasoning_content || msg?.reasoning || null;
    // Nettoyer les espaces en tête/queue résiduels
    if (text) text = text.trim();
  }
  if (!text) {
    const detail = JSON.stringify(data).slice(0, 300);
    throw new Error(`Réponse vide de ${label} — ${detail}`);
  }
  return text;
}

/**
 * Helper partagé addPerso / addLieu — génère un champ de saisie (input ou textarea).
 */
function _cardField(label, field, placeholder, value, multiline = false) {
  const baseStyle = `width:100%;font-size:11px;font-family:'DM Sans',sans-serif;border:1px solid var(--cream);border-radius:3px;background:var(--parchment);color:var(--ink);padding:3px 6px;outline:none;box-sizing:border-box;transition:border-color .12s;`;
  const focus = `onfocus="this.style.borderColor='var(--accent-light)'" onblur="this.style.borderColor='var(--cream)'"`;
  const el = multiline
    ? `<textarea data-field="${field}" rows="2" placeholder="${placeholder}" oninput="markUnsaved()" style="${baseStyle}resize:vertical;" ${focus}>${escHtml(value||'')}</textarea>`
    : `<input type="text" data-field="${field}" placeholder="${placeholder}" value="${escHtml(value||'')}" oninput="markUnsaved()" style="${baseStyle}height:26px;" ${focus}>`;
  return `<div style="margin-bottom:5px;"><div style="font-size:8.5px;text-transform:uppercase;letter-spacing:.07em;color:var(--ink-muted);font-weight:600;margin-bottom:2px;">${label}</div>${el}</div>`;
}


// ── STATE ──────────────────────────────────────────────
const images = {};       // { name: { src, caption } }
let debounceTimer = null;

// ── ÉTAT PROJET ────────────────────────────────────────
let currentProject = {
  nom: '',
  dateCreation: '',
  derniereSauvegarde: null,
};
let _projectPendingAction = null; // 'new' | 'load'
let _hasUnsavedChanges = false;

function markUnsaved() {
  _hasUnsavedChanges = true;
  const dot = document.getElementById('save-dot');
  const lbl = document.getElementById('save-label');
  if (dot) { dot.classList.remove('saved'); dot.classList.add('unsaved'); }
  if (lbl && currentProject.nom) lbl.textContent = _t('unsaved_label');
}

function markSaved() {
  _hasUnsavedChanges = false;
  const dot = document.getElementById('save-dot');
  const lbl = document.getElementById('save-label');
  if (dot) { dot.classList.remove('unsaved'); dot.classList.add('saved'); }
  if (lbl) lbl.textContent = _t('saved_label') + ' ' + new Date().toLocaleTimeString('fr-FR', { hour:'2-digit', minute:'2-digit' });
}

function updateProjectBadge() {
  const badge = document.getElementById('project-badge');
  if (badge) badge.textContent = currentProject.nom ? _t('project_label_prefix') + currentProject.nom : '';
}

// ── MODAL PROJET ───────────────────────────────────────
function openProjectModal() {
  // Reset état de la modale
  _projectPendingAction = null;
  document.getElementById('project-name-area').classList.remove('visible');
  document.getElementById('project-confirm-btn').style.display = 'none';
  document.getElementById('project-skip-btn').style.display = 'inline-block';
  document.getElementById('project-name-input').value = '';
  const _pm_o = document.getElementById('project-modal');
  _pm_o.classList.add('open');
  _pm_o.removeAttribute('inert');
}

function skipProjectModal() {
  const _pm_c = document.getElementById('project-modal');
  _pm_c.classList.remove('open');
  _pm_c.setAttribute('inert', '');
}

function chooseNew() {
  _projectPendingAction = 'new';
  document.getElementById('project-name-area').classList.add('visible');
  document.getElementById('project-confirm-btn').style.display = 'inline-block';
  document.getElementById('project-confirm-btn').textContent = 'Créer le projet';
  document.getElementById('project-skip-btn').style.display = 'inline-block';
  document.getElementById('project-name-input').focus();
}

function chooseLoad() {
  document.getElementById('project-load-input').click();
}

function confirmProjectChoice() {
  if (_projectPendingAction === 'new') {
    // Lire le nom saisi — était indéfini (ReferenceError) avant ce correctif
    const nom = (document.getElementById('project-name-input')?.value || '').trim() || 'Sans titre';
    // Réinitialiser le projet
    setDomVal('raw-input', '');
    Object.keys(images).forEach(k => delete images[k]);
    // Réinitialiser les paramètres par défaut
    setDomVal('font-size', '12');
    setDomVal('line-height', '1.75');
    setDomVal('indent-size', '1.5em');
    setDomVal('page-format', 'A4');
    setDomVal('folio-start', '1');
    // Vider la page de garde et le header courant
    ['pg-titre','pg-auteur','pg-soustitre','pg-genre','header-courant'].forEach(id => setDomVal(id, ''));
    // Vider la fiche œuvre
    ['oeuvre-type','oeuvre-genre','oeuvre-epoque','oeuvre-monde','oeuvre-narration','oeuvre-temps','oeuvre-registre','oeuvre-notes'].forEach(id => setDomVal(id, ''));
    // Vider les fiches personnages et lieux
    const persoList = document.getElementById('perso-list');
    if (persoList) persoList.innerHTML = '';
    _persoCount = 0;
    const lieuList = document.getElementById('lieu-list');
    if (lieuList) lieuList.innerHTML = '';
    _lieuCount = 0;
    // Réinitialiser les métadonnées chapitre
    _chapterMeta = {};
    paginateNodes([], []);
    updateStats();
    updateSubmitInfoBox();
    renderImgList();
    currentProject = { nom, dateCreation: new Date().toISOString(), derniereSauvegarde: null };
    updateProjectBadge();
    document.getElementById('save-dot').classList.remove('saved','unsaved');
    document.getElementById('save-label').textContent = 'Nouveau projet';
    const _pm_c = document.getElementById('project-modal');
  _pm_c.classList.remove('open');
  _pm_c.setAttribute('inert', '');
    showToast(_t('toast_project_created').replace('{nom}', nom));
    _hasUnsavedChanges = false;
    _wgStartWords = 0;
    _lastGoalPct  = 0;
    updateWordGoal();
    updateDailyWordGoal();
    // ── Redirection vers la fiche auteur/œuvre ──────────────────────────
    // On ouvre les paramètres sur l'onglet Œuvre pour inviter l'auteur
    // à renseigner sa fiche. Un bouton "Passer" est affiché temporairement.
    setTimeout(() => {
      _onboardingMode = true;
      openSettingsModal('oeuvre');
      _showOnboardingSkip();
    }, 350);
  } else {
    // Aucune action sélectionnée — guider l'utilisateur
    document.getElementById('project-name-input')?.focus();
  }
}

// ── ONBOARDING NOUVEAU PROJET ──────────────────────────
var _onboardingMode = false;

function _showOnboardingSkip() {
  // Injecter une bannière d'invitation en haut de la modal paramètres
  const modal = document.getElementById('settings-modal');
  if (!modal) return;
  if (modal.querySelector('#onboarding-banner')) return; // déjà présent
  const banner = document.createElement('div');
  banner.id = 'onboarding-banner';
  banner.style.cssText = [
    'position:sticky;top:0;z-index:10;',
    'display:flex;align-items:center;justify-content:space-between;gap:12px;',
    'background:var(--accent);color:#fff;',
    'padding:10px 20px;font-family:\'DM Sans\',sans-serif;font-size:13px;',
    'border-bottom:1px solid rgba(0,0,0,0.15);',
  ].join('');
  banner.innerHTML = `
    <span style="display:flex;align-items:center;gap:8px;">
      <span style="font-size:16px;">✍️</span>
      <span>Prenez un moment pour renseigner votre fiche auteur et œuvre — cela enrichit l'IA et personalise votre export.</span>
    </span>
    <button onclick="_skipOnboarding()" style="
      flex-shrink:0;padding:5px 14px;border-radius:5px;border:1px solid rgba(255,255,255,0.5);
      background:rgba(255,255,255,0.15);color:#fff;cursor:pointer;font-size:12px;
      font-family:'DM Sans',sans-serif;transition:background 0.12s;white-space:nowrap;
    " onmouseover="this.style.background='rgba(255,255,255,0.28)'" onmouseout="this.style.background='rgba(255,255,255,0.15)'">
      Passer pour l'instant →
    </button>`;
  // Insérer avant le premier enfant de la modal
  const box = modal.querySelector('.settings-modal-box') || modal.firstElementChild;
  if (box) box.insertBefore(banner, box.firstChild);
}

function _skipOnboarding() {
  _onboardingMode = false;
  const banner = document.getElementById('onboarding-banner');
  if (banner) banner.remove();
  closeSettingsModal();
  showToast(_t('onboarding_fiche_later'), 2800, 'info');
}

function _hideOnboardingSkip() {
  _onboardingMode = false;
  const banner = document.getElementById('onboarding-banner');
  if (banner) banner.remove();
}

// ── SAUVEGARDE JSON ────────────────────────────────────
function collectProjectData() {
  return {
    version: 3,
    meta: {
      nom: currentProject.nom || 'Mon projet',
      dateCreation: currentProject.dateCreation || new Date().toISOString(),
      derniereSauvegarde: new Date().toISOString(),
      application: APP_VERSION,
    },
    mise_en_page: {
      fontSize:      getDomVal('font-size'),
      lineHeight:    getDomVal('line-height'),
      indentSize:    getDomVal('indent-size'),
      pageFormat:    getDomVal('page-format'),
      folioStart:    getDomVal('folio-start')     || 1,
      headerCourant: getDomVal('header-courant')  || '',
    },
    page_de_garde: {
      titre:     getDomVal('pg-titre'),
      auteur:    getDomVal('pg-auteur'),
      soustitre: getDomVal('pg-soustitre'),
      genre:     getDomVal('pg-genre'),
    },
    fiche_oeuvre: {
      type:      getDomVal('oeuvre-type'),
      genre:     getDomVal('oeuvre-genre'),
      epoque:    getDomVal('oeuvre-epoque'),
      monde:     getDomVal('oeuvre-monde'),
      narration: getDomVal('oeuvre-narration'),
      temps:     getDomVal('oeuvre-temps'),
      registre:  getDomVal('oeuvre-registre'),
      notes:     getDomVal('oeuvre-notes'),
    },
    personnages: getPersos(),
    lieux: getLieux(),
    ia_config: (() => {
      // Exporter ia_config sans les modules (ils restent locaux dans ia_modules_state)
      const cfg = _loadIaConfig();
      const cleanConfigs = {};
      Object.entries(cfg.configs || {}).forEach(([prov, provCfg]) => {
        cleanConfigs[prov] = { key: provCfg.key || '', model: provCfg.model || '' };
        // modules: volontairement exclus du JSON de projet
      });
      return { provider: cfg.provider, configs: cleanConfigs };
    })(),
    texte: (function () {
      var _f = (typeof window !== 'undefined' && window._isolatedGetFullText) ? window._isolatedGetFullText() : null;
      return _f != null ? _f : getDomVal('raw-input');
    })(),
    images: Object.fromEntries(Object.entries(images).map(([k, v]) => [k, { ...v }])),
    chapterMeta: { ..._chapterMeta },
    prompts_ia: collectPrompts(),
    annotations: typeof _ANNOT !== 'undefined' ? _ANNOT.export() : [],
  };
}

function saveProject() {
  if (!currentProject.nom) {
    // Pas de projet actif → ouvrir la modale pour créer un nom
    openProjectModal();
    // openProjectModal() réinitialise elle-même l'état — ne pas appeler chooseNew()
    return;
  }
  const data = collectProjectData();
  currentProject.derniereSauvegarde = data.meta.derniereSauvegarde;

  const json = JSON.stringify(data, null, 2);
  const blob = new Blob([json], { type: 'application/json' });
  const url  = URL.createObjectURL(blob);
  const a    = document.createElement('a');
  // Nom de fichier : projet_slug.json
  const slug = currentProject.nom.toLowerCase().replace(/\s+/g,'-').replace(/[^a-z0-9\-]/g,'').slice(0, 40) || 'projet';
  a.href = url;
  a.download = slug + '.scrivaelo';
  a.click();
  URL.revokeObjectURL(url);
  markSaved();
  showToast(_t('toast_project_saved').replace('{file}', a.download));
}

// ── CHARGEMENT JSON ────────────────────────────────────
function loadProjectFile(event) {
  const file = event.target.files[0];
  if (!file) return;
  const reader = new FileReader();
  reader.onload = (ev) => {
    try {
      const data = JSON.parse(ev.target.result);
      applyProjectData(data, file.name);
    } catch(e) {
      showToast(_t('toast_invalid_file'));
    }
  };
  reader.readAsText(file);
  // Reset input pour permettre le rechargement du même fichier
  event.target.value = '';
}

function applyProjectData(data, fileName) {
  // Vider l'état actuel
  Object.keys(images).forEach(k => delete images[k]);
  setDomVal('raw-input', '');

  // Restaurer le texte
  if (data.texte !== undefined) setDomVal('raw-input', data.texte);

  // Restaurer les paramètres de mise en page
  if (data.mise_en_page) {
    const mp = data.mise_en_page;
    if (mp.fontSize)      setDomVal('font-size',      mp.fontSize);
    if (mp.lineHeight)    setDomVal('line-height',     mp.lineHeight);
    if (mp.indentSize)    setDomVal('indent-size',     mp.indentSize);
    if (mp.pageFormat)    setDomVal('page-format',     mp.pageFormat);
    if (mp.folioStart)    setDomVal('folio-start',     mp.folioStart);
    if (mp.headerCourant) setDomVal('header-courant',  mp.headerCourant);
  }

  // Restaurer la page de garde
  if (data.page_de_garde) {
    const pg = data.page_de_garde;
    if (pg.titre     !== undefined) setDomVal('pg-titre',     pg.titre);
    if (pg.auteur    !== undefined) setDomVal('pg-auteur',    pg.auteur);
    if (pg.soustitre !== undefined) setDomVal('pg-soustitre', pg.soustitre);
    if (pg.genre     !== undefined) setDomVal('pg-genre',     pg.genre);
  }

  // Restaurer la Fiche Œuvre
  if (data.fiche_oeuvre) {
    const fo = data.fiche_oeuvre;
    ['type','genre','epoque','monde','narration','temps','registre','notes'].forEach(k => {
      if (fo[k] !== undefined) setDomVal('oeuvre-' + k, fo[k]);
    });
    const hasData = Object.values(fo).some(v => v && v.trim && v.trim());
    if (hasData) {
      const acc = document.getElementById('acc-oeuvre');
      if (acc && !acc.classList.contains('open')) acc.classList.add('open');
    }
  }

  // Restaurer les Fiches Personnages
  if (data.personnages && Array.isArray(data.personnages)) {
    const list = document.getElementById('perso-list');
    if (list) list.innerHTML = '';
    _persoCount = 0;
    data.personnages.forEach(p => addPerso(p));
    if (data.personnages.length > 0) {
      const acc = document.getElementById('acc-persos');
      if (acc && !acc.classList.contains('open')) acc.classList.add('open');
    }
  }

  // Restaurer les Fiches Lieux
  if (data.lieux && Array.isArray(data.lieux)) {
    const list = document.getElementById('lieu-list');
    if (list) list.innerHTML = '';
    _lieuCount = 0;
    data.lieux.forEach(l => addLieu(l));
    if (data.lieux.length > 0) {
      const acc = document.getElementById('acc-lieux');
      if (acc && !acc.classList.contains('open')) acc.classList.add('open');
    }
  }

  // Restaurer la config IA & clés API (compatible ancien format + nouveau)
  // RÈGLE CRITIQUE : les clés API stockées localement ont TOUJOURS la priorité.
  // Le JSON du projet peut contenir le provider préféré et le modèle,
  // mais on NE remplace JAMAIS les clés API locales par celles du projet.
  if (data.ia_config) {
    const cfg = data.ia_config;
    const localCfg = _loadIaConfig(); // lire la config locale actuelle

    if (cfg.configs && typeof cfg.configs === 'object') {
      // Fusionner : pour chaque provider, garder la clé locale si elle existe
      Object.entries(cfg.configs).forEach(([prov, projProvCfg]) => {
        const localProvCfg = localCfg.configs[prov] || {};
        // Clé locale prioritaire, sinon clé du projet
        const key = (localProvCfg.key || '').trim() || (projProvCfg.key || '').trim();
        const model = projProvCfg.model || localProvCfg.model || '';
        // Ne JAMAIS copier les modules dans ia_config
        localCfg.configs[prov] = { key, model };
      });
      // Appliquer le provider du projet
      if (cfg.provider && AI_PROVIDERS[cfg.provider]) {
        localCfg.provider = cfg.provider;
      }
      _saveIaConfig(localCfg);

    } else if (cfg.api_keys && typeof cfg.api_keys === 'object') {
      // Ancien format → migrer en préservant les clés locales
      Object.entries(cfg.api_keys).forEach(([prov, projKey]) => {
        const localProvCfg = localCfg.configs[prov] || {};
        const key = (localProvCfg.key || '').trim() || (projKey || '').trim();
        const model = localProvCfg.model || '';
        if (key || model) localCfg.configs[prov] = { key, model };
      });
      if (cfg.provider && AI_PROVIDERS[cfg.provider]) {
        localCfg.provider = cfg.provider;
      }
      _saveIaConfig(localCfg);
    }

    // Nettoyer tous les modules qui auraient pu se glisser dans ia_config
    try {
      const cleanCfg = _loadIaConfig();
      let dirty = false;
      Object.keys(cleanCfg.configs || {}).forEach(prov => {
        if (cleanCfg.configs[prov].modules) {
          delete cleanCfg.configs[prov].modules;
          dirty = true;
        }
      });
      if (dirty) _saveIaConfig(cleanCfg);
    } catch(e) {}

    // Activer le provider sauvegardé
    const targetProv = cfg.provider || _wtProvider || 'claude';
    if (AI_PROVIDERS[targetProv] && typeof setAiProvider === 'function') {
      setAiProvider(targetProv);
    }
    // Resynchroniser les modules IA depuis ia_modules_state (débloque les boutons)
    if (typeof loadIaModulesState === 'function') {
      loadIaModulesState(targetProv);
    }
  }

  // Restaurer les images
  if (data.images) Object.entries(data.images).forEach(([k, v]) => { images[k] = { ...v }; });

  // Restaurer les statuts et verrous de chapitres
  _chapterMeta = {};
  if (data.chapterMeta) Object.entries(data.chapterMeta).forEach(([k, v]) => { _chapterMeta[k] = { ...v }; });

  // Restaurer les annotations (nouveau système) + migrer les anciennes balises
  if (typeof _ANNOT !== 'undefined') {
    _ANNOT.clear();
    if (data.annotations && Array.isArray(data.annotations)) {
      _ANNOT.import(data.annotations);
    }
    // Migration automatique des anciennes balises inline
    const ta2 = document.getElementById('raw-input');
    if (ta2) {
      const migrated = _ANNOT.migrateInlineTags(ta2.value);
      if (migrated.changed) {
        ta2.value = migrated.text;
        markUnsaved && markUnsaved();
      }
    }
    clearTimeout(window._annotRenderTimer);
    window._annotRenderTimer = setTimeout(() => _ANNOT.render(), 200);
  }

  // Restaurer les prompts IA personnalisés
  if (data.prompts_ia) applyProjectPrompts(data.prompts_ia);

  // Restaurer les méta
  const meta = data.meta || {};
  currentProject = {
    nom: meta.nom || (fileName ? fileName.replace(/\.(scrivaelo|json)$/i,'') : 'Projet chargé'),
    dateCreation: meta.dateCreation || '',
    derniereSauvegarde: meta.derniereSauvegarde || null,
  };

  updateProjectBadge();
  updateStats();
  updateSubmitInfoBox();
  syncSidebarToFormat();
  renderImgList();
  formatRoman();
  markSaved();

  // Réinitialiser les compteurs d'objectifs de mots APRÈS le chargement du texte.
  const _wcAfterLoad = countWords(getDomVal('raw-input'));
  _wgStartWords = _wcAfterLoad;
  _lastGoalPct  = 0;
  updateWordGoal();
  try {
    localStorage.setItem('atelier_daily_date',  _todayStr());
    localStorage.setItem('atelier_daily_start', String(_wcAfterLoad));
    _dailyGoalPct = 0;
  } catch(e) {}
  updateDailyWordGoal();

  const _pm_c = document.getElementById('project-modal');
  _pm_c.classList.remove('open');
  _pm_c.setAttribute('inert', '');
  showToast(_t('toast_project_loaded').replace('{nom}', currentProject.nom), 3000, 'ok');
}


// ── VUES ───────────────────────────────────────────────
function setView(mode) {
  const ip = document.getElementById('input-pane');
  const pp = document.getElementById('preview-pane');
  ['btn-split','btn-edit','btn-preview'].forEach(id =>
    document.getElementById(id).classList.remove('active'));
  document.getElementById('btn-'+mode).classList.add('active');
  // Utiliser des classes pour contourner les règles CSS !important sur display
  ip.classList.remove('pane-hidden');
  pp.classList.remove('pane-hidden');
  if (mode === 'edit')    pp.classList.add('pane-hidden');
  if (mode === 'preview') ip.classList.add('pane-hidden');
  // Mémoriser la vue courante
  try { localStorage.setItem('atelier_view_mode', mode); } catch(e) {}
}

// ── INPUT ──────────────────────────────────────────────
function onRawInput() {
  // Réinitialiser la recherche si le texte change
  if (_esMatches && _esMatches.length) {
    _esMatches = []; _esCurrent = -1;
    const count = document.getElementById('es-count');
    const btnP  = document.getElementById('es-prev');
    const btnN  = document.getElementById('es-next');
    const ta    = document.getElementById('raw-input');
    if (count) count.textContent = '';
    if (btnP)  btnP.disabled = true;
    if (btnN)  btnN.disabled = true;
    if (ta)    ta.classList.remove('es-searching');
  }
  markUnsaved();
  // Indicateur visuel "recalcul en cours"
  const container = document.getElementById('pages-container');
  if (container) container.style.opacity = '0.5';
  // OPT #5 FIX : updateStats() inclus dans le debounce pour éviter un recomptage
  // complet à chaque frappe sur de longs textes. L'affichage est légèrement retardé
  // (DEBOUNCE_MS) mais reste cohérent avec la pagination.
  clearTimeout(debounceTimer);
  debounceTimer = setTimeout(() => {
    updateStats();
    formatRoman();
    if (container) container.style.opacity = '1';
    if (typeof _ANNOT !== 'undefined') _ANNOT.render();
  }, DEBOUNCE_MS);
}

function updateStats() {
  const text  = getDomVal('raw-input');
  const clean = cleanForCounting(text);

  const words = clean.trim() ? clean.trim().split(/\s+/).filter(w => w.length > 0).length : 0;
  const chars = text.length;
  const lines = text.split('\n');
  let chapters = 0;
  lines.forEach(line => { if (detectHeadingLevel(line.trim()) === 1) chapters++; });

  const fmt = getDomVal('page-format');
  const wordsPerPage = {
    A4: 250, ROMAN: 220, A5: 170, POCHE: 130, SUBMIT_AMI: 1500, SUBMIT_STD: 250,
  }[fmt] || 250;

  let pageLabel = '~' + Math.ceil(words / wordsPerPage);
  if (isSubmitFormat(fmt)) {
    pageLabel = '~' + Math.ceil(chars / 1500) + ' f.';
  }

  document.getElementById('stat-words').textContent    = words.toLocaleString('fr');
  document.getElementById('stat-chars').textContent    = chars.toLocaleString('fr');
  document.getElementById('stat-chapters').textContent = chapters;
  document.getElementById('stat-pages').textContent    = pageLabel;
  const pageLbl = document.getElementById('stat-pages-lbl');
  if (pageLbl) pageLbl.textContent = isSubmitFormat(fmt) ? 'feuillets' : 'pages est.';
}

// ── DÉTECTION STRUCTURE ────────────────────────────────
function detectHeadingLevel(line) {
  const l = line.trim();

  // Exclusions immédiates : dialogue et ponctuation narrative
  // Tiret cadratin ou dialogue : jamais un titre
  if (/^[—–-]/.test(l)) return 0;
  // Guillemets ouvrants = réplique de dialogue
  if (/^[«“"]/.test(l)) return 0;
  // Ligne qui se termine par ! ou ? et n'est pas un mot-clé de chapitre
  if (/[!?]$/.test(l) && !/^(chapitre|chapter|partie|part|livre|book|prologue|épilogue|epilogue)/i.test(l)) return 0;
  // Contient des guillemets typographiques intérieurs = narration/dialogue
  if (/[«»“”]/.test(l)) return 0;

  // H1 — mots-clés explicites de chapitrage
  if (/^(chapitre|chapter)\s+/i.test(l)) return 1;
  if (/^(partie|part|book|livre)\s+/i.test(l)) return 1;
  if (/^(prologue|épilogue|epilogue|incipit|postface|avant-propos|introduction|conclusion)$/i.test(l)) return 1;

  // H1 — chiffre romain seul ou avec séparateur et titre court
  if (/^[IVXivx]+\.?\s*$/.test(l)) return 1;
  if (/^[IVXivx]+\s*[.\-—]\s*[A-Z\u00C0-\u00DC\w]/.test(l) && l.length < 60 && !/[!?]/.test(l)) return 1;

  // H1 — numéro arabe + titre en majuscule
  if (/^[0-9]+\s*[.\-—]\s*[A-Z\u00C0-\u00DC]/.test(l) && l.length < 60 && !/[!?]/.test(l)) return 1;

  // H1 — ligne entièrement en MAJUSCULES stricte
  // Doit avoir au moins 4 lettres, max 50 chars, sans ponctuation de dialogue ni exclamation
  // BUG #8 FIX : exclure les cris narratifs (ligne contenant des espaces ET
  // ressemblant à une phrase courte sans structure de titre : pas de chiffres,
  // pas de mot-clé de chapitre). On exige au moins 2 mots pour les formes libres.
  const letters = l.replace(/[^A-Za-z\u00C0-\u00FF]/g, '');
  const wordCount = l.trim().split(/\s+/).length;
  if (l === l.toUpperCase()
      && letters.length >= 4
      && l.length <= 50
      && !/[!?:,;.…]/.test(l)
      && !/^[—–\-«»"]/.test(l)
      && (wordCount >= 2 || /^(chapitre|chapter|partie|part|livre|book|prologue|épilogue|epilogue|acte|tome)/i.test(l) || /\d/.test(l))) return 1;

  // H2 — séparateur de scène stylistique (* Titre de scène)
  if (/^\*\s+\S/.test(l)) return 2;

  return 0;
}

function isSceneBreak(line) {
  return /^[\*\-~•·=]{2,}\s*$/.test(line.trim()) || /^\s*(\*\s*){2,}\s*$/.test(line);
}

// ── FORMATAGE PRINCIPAL ────────────────────────────────
function formatRoman() {
  _resetRenderNoteIdx();
  const raw = getDomVal('raw-input');
  if (!raw.trim()) { paginateNodes([], []); return; }

  const lines = raw.split('\n');
  const nodes = [];
  let chapters = [];
  let prevWasHeading = false;
  let prevWasEmpty = false;
  let i = 0;

  function makeEl(tag, cls, html) {
    const el = document.createElement(tag);
    if (cls) el.className = cls;
    if (html !== undefined) el.innerHTML = html;
    return el;
  }

  while (i < lines.length) {
    const line = lines[i];
    const trimmed = line.trim();

    if (!trimmed) {
      prevWasEmpty = true;
      i++;
      continue;
    }

    // Image placeholder
    const imgMatch = trimmed.match(/^\[IMAGE:([^\]]+)\]$/i);
    if (imgMatch) {
      const key = imgMatch[1].trim().toLowerCase();
      if (images[key]) {
        const img    = images[key];
        const rot    = img.rotation  || 0;
        const w      = img.width     || 100;
        const align  = img.align     || 'center';
        const valign = img.valign    || 'top';

        // Modes pleine-page (page dédiée)
        const isFullPage = (valign === 'middle' || valign === 'fill');
        // Modes flottants (texte enveloppant)
        const isFloat = (valign === 'float-left' || valign === 'float-right');
        // Mode bandeau (pleine largeur dans le flux)
        const isBandeau = (valign === 'bandeau');
        // Mode filigrane (fond de page, position absolue)
        const isWatermark = (valign === 'watermark');

        const wrapAlign = align === 'left'  ? 'margin-right:auto;margin-left:0'
                        : align === 'right' ? 'margin-left:auto;margin-right:0'
                        : 'margin-left:auto;margin-right:auto';

        const wrap = document.createElement('div');

        let wrapClass = 'book-image';
        if (isFullPage)              wrapClass += ' book-image-fullpage';
        else if (valign === 'float-left')  wrapClass += ' img-float-left';
        else if (valign === 'float-right') wrapClass += ' img-float-right';
        else if (isBandeau)          wrapClass += ' img-bandeau';
        else if (isWatermark)        wrapClass += ' img-watermark';

        wrap.className = wrapClass;

        // Espacement avant/après l'image (en pt) — contrôlé par spaceBefore/spaceAfter
        // null = héritage CSS (16pt haut / 10pt bas par défaut)
        const _sBefore = img.spaceBefore != null ? img.spaceBefore + 'pt' : null;
        const _sAfter  = img.spaceAfter  != null ? img.spaceAfter  + 'pt' : null;

        if (isFloat) {
          wrap.style.cssText = 'width:' + w + '%;position:relative;';
          // Marges CSS par défaut img-float-left/right : 4pt haut, 8pt bas — on override si customisé
          if (_sBefore) wrap.style.setProperty('margin-top',    _sBefore, 'important');
          if (_sAfter)  wrap.style.setProperty('margin-bottom', _sAfter,  'important');
        } else if (isBandeau) {
          wrap.style.cssText = 'width:100%;position:relative;';
          if (_sBefore) wrap.style.setProperty('margin-top',    _sBefore, 'important');
          if (_sAfter)  wrap.style.setProperty('margin-bottom', _sAfter,  'important');
        } else if (isWatermark) {
          // Filigrane : opacité contrôlable (défaut 10%), largeur pilotée par CSS
          const opacityVal = (img.opacity != null) ? img.opacity : 0.10;
          wrap.style.cssText = 'width:' + w + '%;position:relative;opacity:' + opacityVal + ';';
        } else {
          // Flux normal : marges inline avec !important pour survivre à la cascade CSS
          const _mt = _sBefore || '16pt';
          const _mb = _sAfter  || '10pt';
          wrap.style.cssText = 'width:' + w + '%;' + wrapAlign + ';text-align:' + align + ';position:relative;';
          wrap.style.setProperty('margin-top',    _mt, 'important');
          wrap.style.setProperty('margin-bottom', _mb, 'important');
        }

        wrap.dataset.imgKey    = key;
        wrap.dataset.valign    = valign;
        wrap.dataset.isFullPage = isFullPage ? '1' : '0';

        // Tooltip de taille
        const tooltip = document.createElement('div');
        tooltip.className = 'img-size-tooltip';
        tooltip.textContent = w + '%';
        wrap.appendChild(tooltip);

        const im = document.createElement('img');
        im.src = img.src;
        im.alt = img.caption || key;
        im.style.cssText = 'transform:rotate(' + rot + 'deg);max-width:100%;display:block;margin:0 auto;';
        wrap.appendChild(im);

        // Poignées (masquées en mode bandeau et watermark pour éviter confusion)
        if (!isBandeau && !isWatermark) {
          const handleR = document.createElement('div');
          handleR.className = 'img-resize-handle';
          handleR.dataset.side = 'right';
          wrap.appendChild(handleR);

          const handleL = document.createElement('div');
          handleL.className = 'img-resize-handle left';
          handleL.dataset.side = 'left';
          wrap.appendChild(handleL);
        }

        nodes.push(wrap);
        if (img.caption) nodes.push(makeEl('p', 'caption', escHtml(img.caption)));

        // BUG #6 FIX : injecter le clear dans le flux pour éviter que le texte
        // suivant coule sous l'image flottante.
        if (isFloat) {
          const clearEl = document.createElement('div');
          clearEl.className = 'img-float-clear';
          nodes.push(clearEl);
        }
      } else {
        nodes.push(makeEl('p', 'caption', '[Image ' + escHtml(imgMatch[1]) + ' non chargée]'));
      }
      i++; prevWasEmpty = false; prevWasHeading = false;
      continue;
    }

    // Saut de scène
    if (isSceneBreak(trimmed)) {
      nodes.push(makeEl('p', 'scene-break', '* * *'));
      i++; prevWasEmpty = true; prevWasHeading = false;
      continue;
    }

    const level = detectHeadingLevel(trimmed);

    if (level === 1) {
      const id = 'ch-' + chapters.length;
      const el = makeEl('h2', 'chapter-heading', `<span class="chapter-ornament">✦</span>${escHtml(trimmed)}`);
      el.id = id;
      nodes.push(el);
      chapters.push({ id, text: trimmed, level: 1 });
      prevWasHeading = true;
      prevWasEmpty = false;
      i++;
      continue;
    }

    if (level === 2) {
      const id = 'sec-' + chapters.length;
      const el = makeEl('h3', 'section-heading', escHtml(trimmed));
      el.id = id;
      nodes.push(el);
      chapters.push({ id, text: trimmed, level: 2 });
      prevWasHeading = true;
      prevWasEmpty = false;
      i++;
      continue;
    }

    // Paragraphe normal
    const noIndent = prevWasHeading || prevWasEmpty;
    const cls = noIndent ? 'no-indent' : '';
    nodes.push(makeEl('p', cls, renderInlineMarkup(trimmed)));
    prevWasHeading = false;
    prevWasEmpty = false;
    i++;
  }

  paginateNodes(nodes, chapters);
}

function escHtml(s) {
  return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')
          .replace(/"/g,'&quot;').replace(/'/g,'&#39;');
}

/**
 * sanitizeHTML — nettoie du HTML NON FIABLE (sortie IA brute, contenu importé)
 * avant une injection via innerHTML. À réserver au contenu EXTERNE : ne pas
 * l'appliquer aux templates de l'app (ils utilisent volontairement des
 * onclick/style inline que DOMPurify retirerait). Repli sûr sur escHtml si
 * DOMPurify n'est pas chargé.
 */
function sanitizeHTML(html, opts) {
  if (html == null) return '';
  if (typeof DOMPurify !== 'undefined' && DOMPurify && DOMPurify.sanitize) {
    return DOMPurify.sanitize(String(html), opts || {});
  }
  return escHtml(String(html));
}

/** setHTML — équivalent sûr de `el.innerHTML = html` pour du contenu non fiable. */
function setHTML(el, html, opts) {
  if (!el) return;
  el.innerHTML = sanitizeHTML(html, opts);
}

// Compteur global pour indexer les notes dans la preview
let _renderNoteIdx = 0;
function _resetRenderNoteIdx() { _renderNoteIdx = 0; }

// ── Palette de surlignage ──────────────────────────────────────────────────
const HL_COLORS = {
  jaune:   { bg: 'rgba(253,224,71,0.45)',  border: '#ca8a04', label: '🟡', labelFr: 'Jaune',   labelEn: 'Yellow', labelEs: 'Amarillo' },
  rose:    { bg: 'rgba(249,168,212,0.45)', border: '#be185d', label: '🩷', labelFr: 'Rose',    labelEn: 'Pink',   labelEs: 'Rosa'     },
  vert:    { bg: 'rgba(134,239,172,0.45)', border: '#15803d', label: '🟢', labelFr: 'Vert',    labelEn: 'Green',  labelEs: 'Verde'    },
  bleu:    { bg: 'rgba(147,197,253,0.45)', border: '#1d4ed8', label: '🔵', labelFr: 'Bleu',    labelEn: 'Blue',   labelEs: 'Azul'     },
  orange:  { bg: 'rgba(253,186,116,0.45)', border: '#c2410c', label: '🟠', labelFr: 'Orange',  labelEn: 'Orange', labelEs: 'Naranja'  },
  violet:  { bg: 'rgba(196,181,253,0.45)', border: '#7c3aed', label: '🟣', labelFr: 'Violet',  labelEn: 'Purple', labelEs: 'Morado'   },
  rouge:   { bg: 'rgba(252,165,165,0.45)', border: '#dc2626', label: '🔴', labelFr: 'Rouge',   labelEn: 'Red',    labelEs: 'Rojo'     },
  cyan:    { bg: 'rgba(103,232,249,0.45)', border: '#0e7490', label: '🩵', labelFr: 'Cyan',    labelEn: 'Cyan',   labelEs: 'Cian'     },
};

const TAG_COLORS = {
  perso:  { bg: 'rgba(196,181,253,0.3)', border: '#7c3aed', icon: '👤' },
  lieu:   { bg: 'rgba(134,239,172,0.3)', border: '#15803d', icon: '📍' },
  theme:  { bg: 'rgba(253,186,116,0.3)', border: '#c2410c', icon: '💡' },
  temps:  { bg: 'rgba(147,197,253,0.3)', border: '#1d4ed8', icon: '⏱' },
  action: { bg: 'rgba(252,165,165,0.3)', border: '#dc2626', icon: '⚡' },
};

// Rendu inline markdown : **gras**, *italique*, __souligné__, ~~barré~~, [NOTE:…], [HL:…], [TAG:…]
function renderInlineMarkup(rawText) {
  const parts = rawText.split(/(\[NOTE:[^\]]*\]|\[HL:[^\]]*\]|\[TAG:[^\]]*\]|~~[^~]+~~|__[^_]+__|\*\*[^*]+\*\*|\*[^*]+\*)/);
  return parts.map(p => {
    // ── NOTE classique ──────────────────────────────────────
    if (p.startsWith('[NOTE:') && p.endsWith(']')) {
      const txt = p.slice(6, -1).trim();
      const idx = _renderNoteIdx++;
      const key = typeof _noteKey === 'function' ? escHtml(_noteKey(txt)) : escHtml(txt.slice(0,120));
      const meta = _notesMeta[_noteKey(txt)] || {};
      const prioColor = { high: '#dc2626', mid: '#f59e0b', low: '#22c55e', none: '#94a3b8' }[meta.priority || 'none'];
      return `<span class="author-note-hl note-hl-classic" data-note-idx="${idx}" data-note-key="${key}" data-note-text="${escHtml(txt)}" style="--hl-bg:rgba(253,224,71,0.35);--hl-border:#ca8a04;--prio-color:${prioColor}">💬 ${escHtml(txt)}<span class="note-float-popup" role="tooltip"><span class="nfp-prio" style="background:${prioColor}"></span><span class="nfp-text">${escHtml(txt)}</span></span></span>`;
    }

    // ── SURLIGNAGE [HL:couleur texte | note optionnelle] ────
    if (p.startsWith('[HL:') && p.endsWith(']')) {
      const inner = p.slice(4, -1); // "couleur texte | note"
      const firstSpace = inner.indexOf(' ');
      if (firstSpace < 0) return escHtml(p);
      const colorKey = inner.slice(0, firstSpace).toLowerCase().trim();
      const rest = inner.slice(firstSpace + 1);
      const pipeIdx = rest.lastIndexOf('|');
      const displayText = pipeIdx >= 0 ? rest.slice(0, pipeIdx).trim() : rest.trim();
      const noteText    = pipeIdx >= 0 ? rest.slice(pipeIdx + 1).trim() : '';
      const col = HL_COLORS[colorKey] || HL_COLORS['jaune'];
      const noteHtml = noteText
        ? `<span class="note-float-popup" role="tooltip"><span class="nfp-color-dot" style="background:${col.border}"></span><span class="nfp-text">${escHtml(noteText)}</span></span>`
        : '';
      return `<span class="author-note-hl note-hl-color" data-hl-color="${colorKey}" data-note-text="${escHtml(noteText)}" style="--hl-bg:${col.bg};--hl-border:${col.border}">${escHtml(displayText)}${noteHtml}</span>`;
    }

    // ── TAG [TAG:etiquette texte] ────────────────────────────
    if (p.startsWith('[TAG:') && p.endsWith(']')) {
      const inner = p.slice(5, -1);
      const firstSpace = inner.indexOf(' ');
      if (firstSpace < 0) return escHtml(p);
      const tagKey = inner.slice(0, firstSpace).toLowerCase().trim();
      const text   = inner.slice(firstSpace + 1).trim();
      const tc = TAG_COLORS[tagKey] || { bg: 'rgba(148,163,184,0.2)', border: '#64748b', icon: '🏷' };
      return `<span class="author-note-tag" data-tag="${tagKey}" style="--tag-bg:${tc.bg};--tag-border:${tc.border}" title="${tc.icon} ${tagKey}">${escHtml(text)}<sup class="tag-sup" style="color:${tc.border}">${tc.icon}</sup></span>`;
    }

    if (p.startsWith('~~') && p.endsWith('~~')) return '<s>'      + escHtml(p.slice(2,-2)) + '</s>';
    if (p.startsWith('__') && p.endsWith('__')) return '<u>'      + escHtml(p.slice(2,-2)) + '</u>';
    if (p.startsWith('**') && p.endsWith('**')) return '<strong>' + escHtml(p.slice(2,-2)) + '</strong>';
    if (p.startsWith('*')  && p.endsWith('*'))  return '<em>'     + escHtml(p.slice(1,-1)) + '</em>';
    return escHtml(p);
  }).join('');
}

// Page de garde (4.3)
function buildTitlePageNode(dims) {
  const titre     = getDomVal('pg-titre').trim();
  const auteur    = getDomVal('pg-auteur').trim();
  const soustitre = getDomVal('pg-soustitre').trim();
  const genre     = getDomVal('pg-genre').trim();
  if (!titre && !auteur) return null;

  const page = document.createElement('div');
  page.className = 'book-page' + (dims.cls ? ' ' + dims.cls : '');
  page.dataset.isTitlePage = '1';
  page.style.cssText = 'font-size:' + dims.fs + 'pt;line-height:' + dims.lh + ';position:relative;overflow:hidden;display:flex;flex-direction:column;align-items:center;justify-content:center;';

  if (genre) {
    const g = document.createElement('p');
    g.style.cssText = 'font-family:"Source Serif 4",serif;font-size:10pt;letter-spacing:.15em;text-transform:uppercase;color:var(--ink-muted);margin-bottom:48pt;text-align:center;text-indent:0;';
    g.textContent = genre;
    page.appendChild(g);
  }
  if (titre) {
    const t = document.createElement('h1');
    t.className = 'book-title';
    t.textContent = titre;
    page.appendChild(t);
  }
  if (soustitre) {
    const s = document.createElement('p');
    s.className = 'book-subtitle';
    s.textContent = soustitre;
    page.appendChild(s);
  }
  if (auteur) {
    const a = document.createElement('p');
    a.style.cssText = 'font-family:"Source Serif 4",serif;font-size:13pt;color:var(--ink-soft);margin-top:32pt;text-align:center;letter-spacing:.04em;text-indent:0;';
    a.textContent = auteur;
    page.appendChild(a);
  }
  // Folio absent sur la page de titre (convention éditoriale)
  return page;
}

// ── MOTEUR DE PAGINATION V3 — ARCHITECTURE FRAMES ──────────────────────────
//
// Structure :
//   Page normale    → 1 .frame-body  (hauteur = zone contenu complète)
//   Page chapitre   → .frame-header (hauteur fixe CHAPTER_HEADER_MM)
//                   + .frame-body  (hauteur = zone contenu − CHAPTER_HEADER_MM)
//
// La marge basse est uniforme PAR CONSTRUCTION : les frames ont une hauteur
// fixe CSS avec overflow:hidden. Aucune arithmétique de marge nécessaire.
//
// Reflows : 0 pendant la boucle d'assemblage.
//   Phase 1 : 1 reflow — mesure frame-body vide (hauteur disponible en px)
//   Phase 2 : 1 reflow groupé — mesure de tous les nœuds isolément
//   Phase 3 : 0 reflow — assemblage arithmétique + flush DocumentFragment
// ────────────────────────────────────────────────────────────────────────────

// Dimensions de page centralisées (7.1 — source unique pour aperçu ET export Word)
// PAGE_DIMS supprimé — getPageDims() est la source unique des dimensions

// Hauteur du frame-header (zone titre de chapitre), en mm
// Standard édition : espace généreux au-dessus du titre, ~1/4 de page
const CHAPTER_HEADER_MM = { A4: 55, A5: 60 };
const FOLIO_RESERVE_MM  = 3; // espace réservé au folio (bottom: 3mm dans son CSS)

function mmToPx(mm) {
  // Mesure réelle depuis le DOM pour correspondre exactement à la conversion
  // CSS du navigateur (qui peut différer de 3.7795 selon le zoom/écran).
  if (!mmToPx._ruler) {
    const r = document.createElement('div');
    r.style.cssText = 'position:absolute;top:-9999px;left:-9999px;width:100mm;height:100mm;visibility:hidden;pointer-events:none;';
    document.body.appendChild(r);
    mmToPx._ruler = r;
  }
  return mm * (mmToPx._ruler.offsetWidth / 100);
}

function getPageDims() {
  const fmt = getDomVal('page-format');
  const fs  = parseFloat(getDomVal('font-size'));
  const lh  = parseFloat(getDomVal('line-height'));
  const ind = getDomVal('indent-size');

  // ── Formats soumission : A4 double interligne, police imposée ─────────
  if (fmt === 'SUBMIT_AMI') {
    return { fmt:'SUBMIT_AMI', cls:'fmt-submit',
             pageW:210, pageH:297,
             padTop:25, padRight:25, padBot:15, padLeft:30,
             chapterHeaderMm: CHAPTER_HEADER_MM.A4,
             fs: 12, lh: 2.0, ind: '0' };
  }
  if (fmt === 'SUBMIT_STD') {
    return { fmt:'SUBMIT_STD', cls:'fmt-submit',
             pageW:210, pageH:297,
             padTop:25, padRight:25, padBot:15, padLeft:30,
             chapterHeaderMm: CHAPTER_HEADER_MM.A4,
             fs: 12, lh: 2.0, ind: '0' };
  }
  if (fmt === 'ROMAN') {
    return { fmt:'ROMAN', cls:'fmt-roman',
             pageW:135, pageH:215,
             padTop:20, padRight:15, padBot:6, padLeft:18,
             chapterHeaderMm: 65,
             fs, lh, ind };
  }
  if (fmt === 'A5') {
    return { fmt:'A5', cls:'fmt-a5',
             pageW:148, pageH:210,
             padTop:18, padRight:14, padBot:6, padLeft:17,
             chapterHeaderMm: CHAPTER_HEADER_MM.A5,
             fs, lh, ind };
  }
  if (fmt === 'POCHE') {
    return { fmt:'POCHE', cls:'fmt-poche',
             pageW:110, pageH:178,
             padTop:14, padRight:12, padBot:5, padLeft:14,
             chapterHeaderMm: 50,
             fs, lh, ind };
  }
  return { fmt:'A4', cls:'',
           pageW:210, pageH:297,
           padTop:25, padRight:20, padBot:8, padLeft:25,
           chapterHeaderMm: CHAPTER_HEADER_MM.A4,
           fs, lh, ind };
}

function applyNodeStyles(el, dims) {
  if (isSubmitFormat(dims.fmt)) {
    el.style.fontFamily = "'Times New Roman', Georgia, serif";
    el.style.textAlign  = 'left';
    el.style.textIndent = '0';
    el.style.hyphens    = 'none';
    if (el.tagName === 'H2' || el.tagName === 'H3') {
      el.style.fontFamily    = "'Times New Roman', Georgia, serif";
      el.style.fontSize      = '12pt';
      el.style.fontWeight    = 'bold';
      el.style.textAlign     = 'left';
      el.style.fontStyle     = 'normal';
      el.style.textTransform = 'uppercase';
      el.style.letterSpacing = '0.05em';
      el.style.marginTop     = '24pt';
      el.style.marginBottom  = '0';
    }
    return;
  }
  // Correctif : le wrapper .book-image ne doit jamais hériter de text-indent
  if (el.classList && el.classList.contains('book-image')) {
    el.style.textIndent = '0';
    return;
  }
  if (el.tagName === 'P' &&
      !el.classList.contains('no-indent') &&
      !el.classList.contains('scene-break') &&
      !el.classList.contains('caption')) {
    el.style.textIndent = dims.ind;
  }
}

/**
 * Calcule les dimensions des frames en pixels à partir de dims (en mm).
 * Retourne :
 *   frameLeft, frameRight (position absolue depuis bords de page)
 *   contentTop            (top du premier frame = padTop en px)
 *   contentHeight         (hauteur totale dispo = pageH - padTop - padBot - folio)
 *   headerHeight          (hauteur du frame-header, en px)
 *   bodyHeightFull        (frame-body sur page normale = contentHeight)
 *   bodyHeightAfterHeader (frame-body sur page chapitre = contentHeight - headerHeight)
 */
function computeFrameDims(dims) {
  const contentTop    = mmToPx(dims.padTop);
  const contentHeight = mmToPx(dims.pageH - dims.padTop - dims.padBot) - mmToPx(FOLIO_RESERVE_MM);
  const headerHeight  = mmToPx(dims.chapterHeaderMm);
  return {
    frameLeft:             mmToPx(dims.padLeft),
    frameRight:            mmToPx(dims.padRight),
    contentTop,
    contentHeight,
    headerHeight,
    bodyHeightFull:        contentHeight,
    bodyHeightAfterHeader: contentHeight - headerHeight,
  };
}

/**
 * Applique les styles de position/hauteur aux frames d'une page.
 * Appelé UNE SEULE FOIS par page lors de la création — pas de lecture DOM.
 */
function styleFrames(page, fd, hasHeader) {
  const leftPx  = fd.frameLeft  + 'px';
  const rightPx = fd.frameRight + 'px';

  if (hasHeader) {
    const fh = page.querySelector('.frame-header');
    const fb = page.querySelector('.frame-body');
    fh.style.cssText = `top:${fd.contentTop}px;left:${leftPx};right:${rightPx};height:${fd.headerHeight}px;`;
    fb.style.cssText = `top:${fd.contentTop + fd.headerHeight}px;left:${leftPx};right:${rightPx};height:${fd.bodyHeightAfterHeader}px;`;
  } else {
    const fb = page.querySelector('.frame-body');
    fb.style.cssText = `top:${fd.contentTop}px;left:${leftPx};right:${rightPx};height:${fd.bodyHeightFull}px;`;
  }
}

/**
 * Crée une page normale (1 frame-body) ou de chapitre (frame-header + frame-body).
 */
function makePage(dims, fd, pageNum, hasHeader) {
  const page = document.createElement('div');
  page.className = 'book-page' + (dims.cls ? ' ' + dims.cls : '');
  page.style.fontSize   = dims.fs + 'pt';
  page.style.lineHeight = dims.lh;

  const isSubmit = isSubmitFormat(dims.fmt);

  // En-tête courant (format édition seulement) (4.4)
  const headerCourant = getDomVal('header-courant').trim();
  if (headerCourant && !isSubmit) {
    const rh = document.createElement('div');
    rh.className = 'running-header';
    rh.textContent = headerCourant;
    page.appendChild(rh);
  }

  if (hasHeader) {
    const fh = document.createElement('div');
    fh.className = 'frame-header';
    page.appendChild(fh);
  }
  const fb = document.createElement('div');
  fb.className = 'frame-body';
  page.appendChild(fb);

  const folio = document.createElement('div');
  folio.className = 'folio';
  folio.textContent = pageNum;
  page.appendChild(folio);

  styleFrames(page, fd, hasHeader);
  return page;
}

// ── MOTEUR DE PAGINATION V5 — FLUX DANS DES FRAMES (modèle Word / moteur PAO) ───────────────
//
// Modèle mental :
//
//   FLUX DE TEXTE  (source logique — jamais découpée)
//         ↓
//   layout engine natif du navigateur  (kerning, justify, hyphens, ligatures…)
//         ↓  scrollHeight > frameLimit ?
//   overflow → scelle la frame, ouvre la frame suivante, le nœud repart dans le flux
//
// Chaque frame est rendue avec overflow:visible PENDANT le remplissage,
// ce qui permet de lire un scrollHeight exact APRÈS insertion.
// Quand un nœud déborde : on l'ôte, on verrouille la frame (overflow:hidden),
// et le nœud repart au début de la frame suivante.
//
// Aucune estimation, aucun Canvas, aucun probe parallèle.
// Le navigateur fait le vrai layout — on lit juste l'overflow.
// ──────────────────────────────────────────────────────────────────────────────────────────

// Remplaçants stub des fonctions V4 (plus utilisées, conservées pour compatibilité)
const CANVAS_WIDTH_SAFETY = 1;
function buildMeasureCtx(dims) { return { ctx: null, lhPx: 0, fsPx: 0 }; }
function countTextLines()  { return { lineCount: 1 }; }
function measureNodeInLines() { return 1; }
function measureBlockNodePx() { return 0; }
function splitParagraphAtLine(srcNode) { return { fitHTML: srcNode.innerHTML, overflowHTML: '' }; }
function premeasureNodes(nodes) { return nodes.map(() => 0); }

function paginateNodes(nodes, chapters) {
  const container    = document.getElementById('pages-container');
  const _previewPane = document.getElementById('preview-pane');
  const _savedScroll = _previewPane ? _previewPane.scrollTop : 0;

  container.innerHTML = '';

  const dims = getPageDims();
  const fd   = computeFrameDims(dims);

  // ── Cas vide ─────────────────────────────────────────────────────────────
  if (!nodes.length) {
    const titlePage = buildTitlePageNode(dims);
    if (titlePage) {
      const lbl = document.createElement('div');
      lbl.className = 'page-number-label';
      lbl.textContent = 'page de garde';
      container.appendChild(lbl);
      container.appendChild(titlePage);
    } else {
      container.innerHTML =
        '<div style="min-height:400px;display:flex;flex-direction:column;' +
        'align-items:center;justify-content:center;gap:12px;color:var(--ink-muted);text-align:center;">' +
        '<div style="font-size:48px;opacity:0.3;">📖</div>' +
        '<p style="font-size:14px;max-width:220px;line-height:1.6;">Votre roman mis en page apparaîtra ici.</p></div>';
    }
    updateChapterList(chapters);
    return;
  }

  // ── Page de garde ────────────────────────────────────────────────────────
  const titlePage = buildTitlePageNode(dims);
  if (titlePage) {
    const lbl = document.createElement('div');
    lbl.className = 'page-number-label';
    lbl.textContent = 'page de garde';
    container.appendChild(lbl);
    container.appendChild(titlePage);
  }

  const folioStart = parseInt(document.getElementById('folio-start')?.value) || 1;

  // ════════════════════════════════════════════════════════════════════════
  // MOTEUR TeX-INSPIRED — 3 phases distinctes
  //
  //  Phase 1 : MESURE  — chaque nœud mesuré UNE FOIS dans un probe isolé
  //  Phase 2 : LAYOUT  — page-builder purement arithmétique (zéro DOM)
  //  Phase 3 : FLUSH   — insertion des nœuds dans les frames finales
  //
  // Vocabulaire TeX adapté :
  //   VBox    = nœud de contenu avec height connue
  //   Glue    = espace flexible (margin CSS déjà incluse dans offsetHeight)
  //   Penalty = contrainte de coupure (-∞ force, +∞ interdit)
  // ════════════════════════════════════════════════════════════════════════

  // ── PHASE 1 : Probe de mesure ─────────────────────────────────────────
  //
  // Le probe est en position:fixed, hors écran, avec les mêmes styles
  // typographiques que la frame (font-size, line-height, font-family,
  // largeur identique). On y insère chaque nœud SEUL pour lire offsetHeight.
  // On ne touche pas aux frames réelles pendant cette phase.

  // ── PHASE 1 : Probe de mesure ───────────────────────────────────────────
  //
  // CRITIQUE : le probe doit être une vraie .book-page avec une .frame-body
  // pour que TOUS les sélecteurs CSS s'appliquent :
  //   .book-page p { text-align:justify; hyphens:auto; margin-bottom:0; }
  //   .book-page { font-size:...; line-height:...; }
  // Sans ça, le texte dans le probe n'est pas justifié → wrap différent → hauteur fausse.
  //
  // Architecture du probe :
  //   div[position:fixed, hors-écran, visibility:hidden]   ← wrapper de mesure
  //     └── .book-page[fmt-class, font-size, line-height]  ← cascade CSS identique
  //           └── .frame-body[width exacte, overflow:visible] ← zone de mesure
  //
  // On insère chaque nœud SEUL dans probeFrame, on lit offsetHeight, on retire.

  const probeWrapper = document.createElement('div');
  probeWrapper.style.cssText =
    'position:fixed;top:-99999px;left:-99999px;' +
    'visibility:hidden;pointer-events:none;overflow:visible;';
  document.body.appendChild(probeWrapper);

  const probePage = document.createElement('div');
  probePage.className = 'book-page' + (dims.cls ? ' ' + dims.cls : '');
  probePage.style.fontSize   = dims.fs + 'pt';
  probePage.style.lineHeight = dims.lh;
  // Taille de page réelle pour que les sélecteurs de format s'appliquent
  probePage.style.width    = mmToPx(dims.pageW) + 'px';
  probePage.style.height   = mmToPx(dims.pageH) + 'px';
  probePage.style.overflow = 'visible';
  probeWrapper.appendChild(probePage);

  const probeFrame = document.createElement('div');
  probeFrame.className = 'frame-body';
  // Largeur identique à la vraie frame-body
  probeFrame.style.cssText =
    'position:absolute;overflow:visible;box-sizing:border-box;' +
    'left:' + fd.frameLeft + 'px;' +
    'right:' + fd.frameRight + 'px;' +
    'top:' + fd.contentTop + 'px;' +
    'height:auto;';
  probePage.appendChild(probeFrame);

  // Mesure réelle de bodyHeightFull depuis le DOM :
  // On crée une frame-body temporaire avec la hauteur exacte que styleFrames
  // lui appliquera (fd.bodyHeightFull px), et on lit son offsetHeight.
  // Cela capture les arrondis navigateur et évite toute dérive cumulative.
  const probeBodyMeasure = document.createElement('div');
  probeBodyMeasure.className = 'frame-body';
  probeBodyMeasure.style.cssText =
    'position:absolute;overflow:hidden;box-sizing:border-box;' +
    'left:' + fd.frameLeft + 'px;' +
    'right:' + fd.frameRight + 'px;' +
    'top:' + fd.contentTop + 'px;' +
    'height:' + fd.bodyHeightFull + 'px;';
  probePage.appendChild(probeBodyMeasure);
  const realBodyHeightFull = probeBodyMeasure.offsetHeight;
  probePage.removeChild(probeBodyMeasure);
  // Remplacer fd.bodyHeightFull par la valeur réellement rendue
  fd.bodyHeightFull = realBodyHeightFull;

  const LINE_HEIGHT_PX = mmToPx(dims.fs * 0.352778 * dims.lh); // 1 ligne en px
  const PENALTY_WIDOW  = LINE_HEIGHT_PX * 1.5; // seuil orpheline

  // Limite de saut de page pour les pages normales (sans header de chapitre).
  // On soustrait une constante de confort de 3 lignes pour absorber les arrondis
  // de conversion mm→px entre le moteur de calcul et le rendu navigateur.
  const normalFrameLimit = fd.bodyHeightFull - (LINE_HEIGHT_PX * 3);

  // VBox : { srcNode, el (cloné+stylé), height, isChapter, isFullPage, isWatermark }
  const vboxes = [];

  function resolveMm(val, fallback) {
    const n = parseFloat(val);
    return (val === null || val === undefined || val === '' || isNaN(n)) ? fallback : n;
  }

  for (let ni = 0; ni < nodes.length; ni++) {
    const srcNode     = nodes[ni];
    const isChapter   = !!(srcNode.classList && srcNode.classList.contains('chapter-heading'));
    const isFullPage  = !!(srcNode.dataset && srcNode.dataset.isFullPage === '1');
    const isWatermark = !!(srcNode.dataset && srcNode.dataset.valign === 'watermark');

    // Nœuds plein-page / filigrane : pas de mesure, traitement direct au flush
    if (isFullPage || isWatermark) {
      vboxes.push({ srcNode, el: null, height: 0, isChapter: false, isFullPage, isWatermark });
      continue;
    }

    // Titre de chapitre : pas de mesure nécessaire — la hauteur réservée est fd.headerHeight
    if (isChapter) {
      vboxes.push({ srcNode, el: null, height: 0, isChapter: true, isFullPage: false, isWatermark: false });
      continue;
    }

    // Nœud de flux : mesure dans le probe
    // Le nœud est inséré SEUL dans probeFrame (même cascade CSS que la vraie frame)
    const el = srcNode.cloneNode(true);
    applyNodeStyles(el, dims);

    probeFrame.innerHTML = '';
    probeFrame.appendChild(el);
    const h = probeFrame.offsetHeight;  // hauteur calculée par le vrai layout CSS

    vboxes.push({ srcNode, el, height: h, isChapter: false, isFullPage: false, isWatermark: false });
  }


  // Nettoyer le probe — plus besoin
  document.body.removeChild(probeWrapper);

  // ── PHASE 2 : Page-builder arithmétique ──────────────────────────────
  //
  // On parcourt les vboxes et on construit un plan de pages :
  // plan = tableau de PagePlan { hasHeader, chapterNode, items[] }
  // items = tableau de vboxes à placer dans cette frame
  //
  // Penalties TeX :
  //   chapter-heading → force une nouvelle page (penalty = -∞)
  //   titre en dernière position sur une page → interdit (penalty = +∞)
  //     → on anticipe : si le prochain nœud est un chapitre ET qu'on est
  //       à moins d'une ligne de hauteur de la limite → on coupe avant.

  const pages = []; // PagePlan[]

  function newPage(hasHeader, chapterNode) {
    const p = { hasHeader: hasHeader || false, chapterNode: chapterNode || null, items: [] };
    pages.push(p);
    return p;
  }

  // NE PAS pré-créer de page : la première est créée au premier nœud de flux,
  // ou par le premier chapter-heading. Évite les pages vides en tête.
  let currentPage = null;
  let cursor = 0;
  let frameLimit = normalFrameLimit;

  function ensureNormalPage() {
    if (!currentPage) {
      currentPage = newPage(false, null);
      cursor = 0;
      frameLimit = normalFrameLimit;
    }
  }

  for (let vi = 0; vi < vboxes.length; vi++) {
    const vb = vboxes[vi];

    // ── Chapitre : nouvelle page forcée (penalty -∞) ──────────────────
    if (vb.isChapter) {
      currentPage = newPage(true, vb.srcNode);
      cursor = 0;
      // Exception première page de chapitre :
      // Le frame-header occupe fd.headerHeight px. On soustrait également
      // une constante de confort de 3 lignes pour absorber les arrondis
      // de conversion mm→px et les micro-décalages de rendu CSS.
      frameLimit = fd.bodyHeightFull - fd.headerHeight - (LINE_HEIGHT_PX * 3);
      continue;
    }

    // ── Pleine page / filigrane : page dédiée ou overlay ─────────────
    if (vb.isFullPage) {
      const fpPage = newPage(false, null);
      fpPage.isFullPage = true;
      fpPage.fullPageNode = vb.srcNode;
      currentPage = null;
      cursor = 0;
      frameLimit = normalFrameLimit;
      continue;
    }
    if (vb.isWatermark) {
      ensureNormalPage();
      currentPage.watermarkNode = vb.srcNode;
      continue;
    }

    ensureNormalPage();

    const fits = (cursor + vb.height) <= frameLimit;

    if (!fits) {
      if (currentPage.items.length === 0) {
        currentPage.items.push(vb);
        cursor += vb.height;
      } else {
        // Saut de page normale → normalFrameLimit
        currentPage = newPage(false, null);
        cursor = 0;
        frameLimit = normalFrameLimit;
        currentPage.items.push(vb);
        cursor += vb.height;
      }
    } else {
      currentPage.items.push(vb);
      cursor += vb.height;
    }
  }

  // ── PHASE 3 : Flush DOM ───────────────────────────────────────────────
  //
  // On parcourt le plan et on construit les pages HTML.
  // Aucune mesure ici — tout est déjà connu.

  let pageNum = folioStart;

  for (let pi = 0; pi < pages.length; pi++) {
    const plan = pages[pi];

    // ── Page plein-page image ─────────────────────────────────────────
    if (plan.isFullPage && plan.fullPageNode) {
      const srcNode = plan.fullPageNode;
      const key    = srcNode.dataset.imgKey;
      const imgDat = images[key] || {};
      const valign = srcNode.dataset.valign || 'middle';
      const rot    = imgDat.rotation || 0;
      const rotCSS = rot ? 'rotate(' + rot + 'deg)' : '';

      const mT = mmToPx(resolveMm(imgDat.marginTop,   dims.padTop));
      const mB = mmToPx(resolveMm(imgDat.marginBot,   dims.padBot));
      const mL = mmToPx(resolveMm(imgDat.marginLeft,  dims.padLeft));
      const mR = mmToPx(resolveMm(imgDat.marginRight, dims.padRight));
      const availW = Math.max(1, mmToPx(dims.pageW) - mL - mR);
      const availH = Math.max(1, mmToPx(dims.pageH) - mT - mB);
      const imgW   = availW * (imgDat.width || 100) / 100;

      const dedicatedPage = document.createElement('div');
      dedicatedPage.className = 'book-page' + (dims.cls ? ' ' + dims.cls : '');
      dedicatedPage.style.cssText = 'font-size:' + dims.fs + 'pt;line-height:' + dims.lh + ';position:relative;overflow:visible;';
      dedicatedPage.dataset.isFullPageImg = '1';
      dedicatedPage.dataset.imgKey        = key;
      dedicatedPage.dataset.valign        = valign;
      dedicatedPage.dataset.userWpct      = imgDat.width || 100;
      dedicatedPage.dataset.align         = imgDat.align || 'center';
      dedicatedPage.dataset.rotation      = rot;
      dedicatedPage.dataset.marginTopMm   = resolveMm(imgDat.marginTop,   dims.padTop);
      dedicatedPage.dataset.marginBotMm   = resolveMm(imgDat.marginBot,   dims.padBot);
      dedicatedPage.dataset.marginLeftMm  = resolveMm(imgDat.marginLeft,  dims.padLeft);
      dedicatedPage.dataset.marginRightMm = resolveMm(imgDat.marginRight, dims.padRight);

      const jc = imgDat.align === 'left' ? 'flex-start' : imgDat.align === 'right' ? 'flex-end' : 'center';
      const imgContainer = document.createElement('div');
      imgContainer.style.cssText =
        'position:absolute;left:' + mL + 'px;top:' + mT + 'px;' +
        'width:' + availW + 'px;height:' + availH + 'px;' +
        'display:flex;align-items:' + (valign === 'fill' ? 'stretch' : 'center') + ';' +
        'justify-content:' + jc + ';overflow:visible;';

      const imgEl = document.createElement('img');
      imgEl.src = imgDat.src || '';
      imgEl.alt = imgDat.caption || key;
      imgEl.style.cssText = (valign === 'fill')
        ? 'width:' + imgW + 'px;height:' + availH + 'px;object-fit:cover;display:block;flex-shrink:0;' + (rotCSS ? 'transform:' + rotCSS + ';' : '')
        : 'width:' + imgW + 'px;height:auto;display:block;object-fit:contain;flex-shrink:0;' + (rotCSS ? 'transform:' + rotCSS + ';' : '');
      imgContainer.appendChild(imgEl);

      if (imgDat.caption) {
        const cap = document.createElement('p');
        cap.className = 'caption';
        cap.style.cssText = 'position:absolute;bottom:' + Math.max(4, mB - 16) + 'px;left:' + mL + 'px;right:' + mR + 'px;text-align:center;margin:0;';
        cap.textContent = imgDat.caption;
        dedicatedPage.appendChild(cap);
      }

      const folio = document.createElement('div');
      folio.className = 'folio';
      folio.textContent = pageNum;
      const lbl = document.createElement('div');
      lbl.className = 'page-number-label';
      lbl.textContent = 'page ' + pageNum;

      dedicatedPage.appendChild(imgContainer);
      dedicatedPage.appendChild(folio);
      container.appendChild(lbl);
      container.appendChild(dedicatedPage);
      pageNum++;
      continue;
    }

    // ── Page normale ou de chapitre ───────────────────────────────────
    const lbl = document.createElement('div');
    lbl.className = 'page-number-label';
    lbl.textContent = pi === 0 ? 'page ' + pageNum : 'page ' + pageNum;

    const pg = makePage(dims, fd, pageNum, plan.hasHeader);

    // Remplir le frame-header si page de chapitre
    if (plan.hasHeader && plan.chapterNode) {
      const fh = pg.querySelector('.frame-header');
      const chEl = plan.chapterNode.cloneNode(true);
      applyNodeStyles(chEl, dims);
      fh.appendChild(chEl);
      fh.style.overflow = 'hidden';
    }

    // Remplir le frame-body avec les items du plan
    const fb = pg.querySelector('.frame-body');
    fb.style.overflow = 'hidden'; // toujours hidden — la mesure est déjà faite
    const frag = document.createDocumentFragment();
    for (const vb of plan.items) {
      // Réutiliser l'élément déjà cloné+stylé de la phase 1
      frag.appendChild(vb.el);
    }
    fb.appendChild(frag);

    // Filigrane éventuel
    if (plan.watermarkNode) {
      const wm = plan.watermarkNode.cloneNode(true);
      applyNodeStyles(wm, dims);
      pg.style.position = 'relative';
      pg.style.overflow = 'hidden';
      pg.appendChild(wm);
    }

    container.appendChild(lbl);
    container.appendChild(pg);
    pageNum++;
  }

  updateChapterList(chapters);
  renderImgList();

  if (_previewPane && _savedScroll > 0) {
    requestAnimationFrame(() => { _previewPane.scrollTop = _savedScroll; });
  }
}

// ── PARAMÈTRES TYPO ────────────────────────────────────
function applySettings() {
  markUnsaved();
  // Synchroniser les contrôles de la sidebar avec les valeurs réelles du modèle
  syncSidebarToFormat();
  updateStats(); // recalcule pages selon le nouveau format
  updateSubmitInfoBox();
  formatRoman();
}

/**
 * Met à jour les selects de la sidebar pour refléter les valeurs
 * réellement utilisées par le modèle actif (ex: soumission impose
 * interligne 2.0 et tabulation 0).
 */
function syncSidebarToFormat() {
  const isSubmit = isSubmitFormat();
  const lhSel  = document.getElementById('line-height');
  const indSel = document.getElementById('indent-size');
  const fsSel  = document.getElementById('font-size');

  if (isSubmit) {
    lhSel.value  = '2.0';
    indSel.value = '1em';
    fsSel.value  = '12';
    lhSel.disabled = indSel.disabled = fsSel.disabled = true;
    lhSel.title  = 'Fixé par le format de soumission';
    indSel.title = 'Sans tabulation en mode soumission';
    fsSel.title  = 'Fixé par le format de soumission (12 pt)';
  } else {
    lhSel.disabled = indSel.disabled = fsSel.disabled = false;
    lhSel.title = indSel.title = fsSel.title = '';
  }
}

// Données des formats soumission pour l'encart d'info
